mapper.select:
SELECT l.id, l.call_time, l.module_key, l.model_name, l.agent_id, a.name AS agent_name, l.scene_id, sc.name AS scene_name, l.skill_id, l.tokens_input, l.tokens_output, l.duration_ms, l.cost_yuan, l.status, l.error_message, l.created_at FROM ai_token_usage_log l LEFT JOIN ai_agent a ON l.agent_id = a.id LEFT JOIN ai_scene sc ON l.scene_id = sc.id
1 = 1 AND l.call_time >= #{startDate} AND l.call_time <= CONCAT(#{endDate}, ' 23:59:59') AND l.model_name = #{modelName} AND l.module_key = #{moduleKey} AND l.status = #{status}
ORDER BY l.call_time DESC
